// Define all services to check
const services = [
  { name: 'Flask API', url: 'http://localhost:5000/health', type: 'http', critical: true },
  { name: 'Flask API Scraper', url: 'http://localhost:5000/api/status', type: 'http', critical: true },
  { name: 'n8n', url: 'http://localhost:5678/healthz', type: 'http', critical: false },
  { name: 'PuraEstate Frontend', url: 'https://puraestate.co.za', type: 'http', critical: true },
  { name: 'PuraEstate API', url: 'https://api.puraestate.co.za/health', type: 'http', critical: true },
  { name: 'Redis Cache', url: 'redis://localhost:6379', type: 'redis', critical: false }
];

return services.map(s => ({ json: s }));

const serviceInfo = $('Define Services to Check').item.json;
const response = $input.first().json;

const statusCode = response.statusCode || response.status || 0;
const isUp = statusCode >= 200 && statusCode < 400;
const responseTime = response.headers?.['x-response-time'] || 'N/A';

const now = new Date().toISOString();

return [{
  json: {
    service_name: serviceInfo.name,
    service_url: serviceInfo.url,
    service_type: serviceInfo.type,
    critical: serviceInfo.critical,
    is_up: isUp,
    status_code: statusCode,
    response_time: responseTime,
    error: isUp ? null : (response.message || `HTTP ${statusCode}`),
    checked_at: now
  }
}];

